//! Trajectory deposits — the typed shape that lands in graphiti episodic
//! memory at `#4.4.4.4-{anchor}` per kernel-spec §7.
//!
//! A deposit records one matheme-cycle (8 elements) plus the resonance
//! contribution generated by the cycle. It is consumed by:
//!
//! - the graphiti episodic-memory adapter (S3) for persistence
//! - the EBM training pipeline (S5) for accumulating (resonance, energy)
//!   pairs
//! - the verifier (M0/Anuttara) for structural-constraint checking
//!
//! [`TrajectoryDepositRef`] is the lightweight pointer carried inside a
//! [`crate::KernelTickEnvelope`] when a deposit has been recorded for
//! the tick.

use serde::{Deserialize, Serialize};

use portal_core::{BioQuaternionState, EnergyDecomposition, KernelElement, ResonanceVector72};

/// One element-record from an 8-element matheme cycle.
#[derive(Clone, Debug, PartialEq, Serialize, Deserialize)]
pub struct TrajectoryElement {
    pub element: KernelElement,
    pub sub_tick: u8,
    pub bioquaternion: BioQuaternionState,
    pub energy: EnergyDecomposition,
    /// Optional natural-language note from the LLM-Nara articulation
    /// produced during this element.
    pub note: Option<String>,
}

impl TrajectoryElement {
    pub fn new(
        element: KernelElement,
        sub_tick: u8,
        bioquaternion: BioQuaternionState,
        energy: EnergyDecomposition,
    ) -> Result<Self, &'static str> {
        if sub_tick >= 12 {
            return Err("sub_tick must be < 12");
        }
        Ok(Self {
            element,
            sub_tick,
            bioquaternion,
            energy,
            note: None,
        })
    }

    pub fn with_note(mut self, note: impl Into<String>) -> Self {
        self.note = Some(note.into());
        self
    }
}

/// A typed trajectory deposit. Equivalent to one session's
/// matheme-cycle log, addressable in graphiti.
#[derive(Clone, Debug, PartialEq, Serialize, Deserialize)]
pub struct TrajectoryDeposit {
    /// Unique identifier for the deposit (uuid v4).
    pub deposit_id: String,
    pub session_key: String,
    /// The personal-pratibimba anchor — typically `#4.4.4.4-{identity}`.
    pub anchor_coordinate: String,
    /// The canonical bimba coordinate the deposit is rooted against.
    pub canonical_coordinate: String,
    /// Reference into graphiti episodic memory once persisted.
    pub graphiti_arc_id: Option<String>,
    pub started_at_ms: u64,
    pub ended_at_ms: Option<u64>,
    pub elements: Vec<TrajectoryElement>,
    pub resonance_contribution: Option<ResonanceVector72>,
    pub resonance_target: Option<ResonanceVector72>,
    pub r_energy_total: f32,
    /// Subsystem that performed the deposit. Default "S5 episodic
    /// invocation" per gateway-contract `GRAPHITI_INVOCATION_OWNER`.
    pub depositor: String,
}

impl TrajectoryDeposit {
    pub const DEFAULT_DEPOSITOR: &'static str = "S5 episodic invocation";
    pub const PERSONAL_ANCHOR_PREFIX: &'static str = "#4.4.4.4";

    pub fn new(
        session_key: impl Into<String>,
        anchor_coordinate: impl Into<String>,
        canonical_coordinate: impl Into<String>,
        started_at_ms: u64,
    ) -> Result<Self, &'static str> {
        let session_key = session_key.into();
        let anchor_coordinate = anchor_coordinate.into();
        let canonical_coordinate = canonical_coordinate.into();
        if session_key.trim().is_empty() {
            return Err("session key is required");
        }
        if anchor_coordinate.trim().is_empty() {
            return Err("anchor coordinate is required");
        }
        if canonical_coordinate.trim().is_empty() {
            return Err("canonical coordinate is required");
        }
        if started_at_ms == 0 {
            return Err("started_at_ms is required");
        }
        Ok(Self {
            deposit_id: uuid::Uuid::new_v4().to_string(),
            session_key,
            anchor_coordinate,
            canonical_coordinate,
            graphiti_arc_id: None,
            started_at_ms,
            ended_at_ms: None,
            elements: Vec::new(),
            resonance_contribution: None,
            resonance_target: None,
            r_energy_total: 0.0,
            depositor: Self::DEFAULT_DEPOSITOR.to_owned(),
        })
    }

    pub fn with_deposit_id(mut self, deposit_id: impl Into<String>) -> Self {
        self.deposit_id = deposit_id.into();
        self
    }

    pub fn push_element(&mut self, element: TrajectoryElement) -> Result<(), &'static str> {
        if self.elements.len() >= 8 {
            return Err("a matheme cycle has at most 8 elements");
        }
        self.elements.push(element);
        Ok(())
    }

    pub fn close(&mut self, ended_at_ms: u64, r_energy_total: f32) -> Result<(), &'static str> {
        if ended_at_ms < self.started_at_ms {
            return Err("ended_at_ms must be >= started_at_ms");
        }
        if !r_energy_total.is_finite() || r_energy_total < 0.0 {
            return Err("r_energy_total must be finite and non-negative");
        }
        self.ended_at_ms = Some(ended_at_ms);
        self.r_energy_total = r_energy_total;
        Ok(())
    }

    /// Build a reference suitable for embedding in a
    /// [`crate::KernelTickEnvelope`].
    pub fn as_ref(&self) -> TrajectoryDepositRef {
        TrajectoryDepositRef {
            deposit_id: self.deposit_id.clone(),
            session_key: self.session_key.clone(),
            anchor_coordinate: self.anchor_coordinate.clone(),
            canonical_coordinate: self.canonical_coordinate.clone(),
            graphiti_arc_id: self.graphiti_arc_id.clone(),
        }
    }
}

/// Lightweight reference to a deposit, embeddable in a tick envelope
/// without carrying the full element-log.
#[derive(Clone, Debug, PartialEq, Eq, Serialize, Deserialize)]
pub struct TrajectoryDepositRef {
    pub deposit_id: String,
    pub session_key: String,
    pub anchor_coordinate: String,
    pub canonical_coordinate: String,
    pub graphiti_arc_id: Option<String>,
}

#[cfg(test)]
mod tests {
    use super::*;
    use portal_core::EnergyDecomposition;

    fn sample_energy() -> EnergyDecomposition {
        EnergyDecomposition {
            bimba_pratibimba_energy: 0.1,
            lens_energy: 0.05,
            r_energy: 0.02,
            total_energy: 0.17,
        }
    }

    fn sample_bq() -> BioQuaternionState {
        BioQuaternionState::new([1.0, 0.0, 0.0, 0.0], [0.5, 0.5, 0.5, 0.5])
    }

    #[test]
    fn deposit_construction_requires_real_inputs() {
        assert!(TrajectoryDeposit::new("", "#4.4.4.4-frank", "M2-1-3", 1).is_err());
        assert!(TrajectoryDeposit::new("session-1", "", "M2-1-3", 1).is_err());
        assert!(TrajectoryDeposit::new("session-1", "#4.4.4.4-frank", "", 1).is_err());
        assert!(TrajectoryDeposit::new("session-1", "#4.4.4.4-frank", "M2-1-3", 0).is_err());
        let ok = TrajectoryDeposit::new("session-1", "#4.4.4.4-frank", "M2-1-3", 100).unwrap();
        assert!(!ok.deposit_id.is_empty());
        assert_eq!(ok.depositor, TrajectoryDeposit::DEFAULT_DEPOSITOR);
    }

    #[test]
    fn deposit_caps_elements_at_eight_and_validates_close() {
        let mut deposit = TrajectoryDeposit::new("s", "#4.4.4.4-a", "M2-1-3", 100).unwrap();
        for tick in 0..8u8 {
            let elem = TrajectoryElement::new(
                KernelElement::BimbaEncoding,
                tick % 12,
                sample_bq(),
                sample_energy(),
            )
            .unwrap();
            deposit.push_element(elem).unwrap();
        }
        let ninth = TrajectoryElement::new(
            KernelElement::EnrichedReturn,
            8,
            sample_bq(),
            sample_energy(),
        )
        .unwrap();
        assert!(deposit.push_element(ninth).is_err());

        assert!(deposit.close(50, 0.1).is_err()); // ended < started
        assert!(deposit.close(200, -0.1).is_err()); // negative r_energy
        deposit.close(200, 0.42).unwrap();
        assert_eq!(deposit.ended_at_ms, Some(200));
    }

    #[test]
    fn element_rejects_invalid_sub_tick() {
        assert!(TrajectoryElement::new(
            KernelElement::BimbaEncoding,
            12,
            sample_bq(),
            sample_energy()
        )
        .is_err());
    }

    #[test]
    fn deposit_ref_round_trips() {
        let mut deposit = TrajectoryDeposit::new("s", "#4.4.4.4-a", "M2-1-3", 100).unwrap();
        deposit.graphiti_arc_id = Some("arc-1".to_owned());
        let r = deposit.as_ref();
        let json = serde_json::to_string(&r).unwrap();
        let restored: TrajectoryDepositRef = serde_json::from_str(&json).unwrap();
        assert_eq!(r, restored);
        assert_eq!(restored.graphiti_arc_id.as_deref(), Some("arc-1"));
    }

    #[test]
    fn full_deposit_serde_round_trip() {
        let mut deposit = TrajectoryDeposit::new("s", "#4.4.4.4-a", "M2-1-3", 100).unwrap();
        let elem = TrajectoryElement::new(
            KernelElement::PratibimbaPrehension,
            1,
            sample_bq(),
            sample_energy(),
        )
        .unwrap()
        .with_note("prehensive analysis");
        deposit.push_element(elem).unwrap();
        deposit.resonance_contribution = Some(ResonanceVector72::default());
        deposit.close(200, 0.3).unwrap();
        let json = serde_json::to_string(&deposit).unwrap();
        let restored: TrajectoryDeposit = serde_json::from_str(&json).unwrap();
        assert_eq!(deposit, restored);
    }
}
